
// src/font/NirmalaUI.js
export const loadNirmalaFont = (doc) => {
  var font = "";

  // Attach font into jsPDF instance
  doc.addFileToVFS("NirmalaUI-Regular.ttf", font);
  doc.addFont("NirmalaUI-Regular.ttf", "NirmalaUI", "normal");
  doc.addFont("NirmalaUI-Regular.ttf", "NirmalaUI", "bold");
  doc.addFont("NirmalaUI-Regular.ttf", "NirmalaUI", "italic");
  doc.addFont("NirmalaUI-Regular.ttf", "NirmalaUI", "bolditalic");
};
